use gnosis_chaos::{digest_analysis_run, AnalysisCard, FrfStep, TwinVoidDial};
use gnosis_frf::closed_loop::{
    measure_closed_loop_benchmark, ClosedLoopBenchmarkEnvelope,
    CLOSED_LOOP_RUNTIME_METADATA_DIRECTIVE,
};
use serde::Serialize;
use std::env;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::Instant;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
#[serde(rename_all = "kebab-case")]
enum Conclusion {
    Secure,
    WeaknessFound,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
struct Finding {
    family: &'static str,
    claim: &'static str,
    weakness: &'static str,
    severity: &'static str,
    node_id: String,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
#[serde(rename_all = "camelCase")]
struct SearchBracket {
    raw_state_upper_bound: usize,
    bracketed_state_upper_bound: usize,
    representative_count: usize,
    pruned_state_estimate: usize,
    chaos_pressure_digest: u64,
}

#[derive(Debug, Clone, Serialize)]
#[serde(rename_all = "camelCase")]
struct AuditReport {
    ok: bool,
    conclusion: Conclusion,
    node_count: usize,
    edge_count: usize,
    findings: Vec<Finding>,
    search_bracket: SearchBracket,
    elapsed_nanos: u128,
    frf_certified: bool,
}

#[derive(Debug, Clone)]
struct GgNode {
    id: String,
    label: String,
    properties: String,
    normalized_properties: String,
}

#[derive(Debug, Clone, Copy)]
enum Mode {
    Smoke,
    Bench,
}

fn default_target() -> PathBuf {
    PathBuf::from("../examples/crypto/password-digest-md5-toy.gg")
}

fn parse_mode(args: &[String]) -> Mode {
    if args.iter().any(|arg| arg == "--bench") {
        Mode::Bench
    } else {
        Mode::Smoke
    }
}

fn parse_iterations(args: &[String]) -> usize {
    args.iter()
        .filter_map(|arg| arg.parse::<usize>().ok())
        .find(|value| *value > 0)
        .unwrap_or(25)
}

fn parse_target(args: &[String]) -> PathBuf {
    args.iter()
        .position(|arg| arg == "--target")
        .and_then(|index| args.get(index + 1))
        .map(PathBuf::from)
        .unwrap_or_else(default_target)
}

fn normalize_token(value: &str) -> String {
    let mut normalized = String::with_capacity(value.len());
    for byte in value.bytes() {
        if byte.is_ascii_alphanumeric() {
            normalized.push(byte.to_ascii_lowercase() as char);
        }
    }
    normalized
}

fn property_number(properties: &str, key: &str) -> Option<usize> {
    let key_pos = properties.find(key)?;
    let tail = &properties[key_pos + key.len()..];
    let quote_start = tail.find('\'')?;
    let tail = &tail[quote_start + 1..];
    let quote_end = tail.find('\'')?;
    tail[..quote_end].parse().ok()
}

fn parse_nodes(source: &str) -> Vec<GgNode> {
    let mut nodes = Vec::new();
    let mut current = String::new();

    for line in source.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with("//") || trimmed.contains(")-[") {
            continue;
        }

        if trimmed.starts_with('(') && !current.is_empty() {
            push_node(&current, &mut nodes);
            current.clear();
        }

        if trimmed.starts_with('(') || !current.is_empty() {
            current.push_str(trimmed);
            current.push(' ');
            if trimmed.ends_with(')') {
                push_node(&current, &mut nodes);
                current.clear();
            }
        }
    }

    if !current.is_empty() {
        push_node(&current, &mut nodes);
    }

    nodes
}

fn push_node(raw: &str, nodes: &mut Vec<GgNode>) {
    let Some(colon) = raw.find(':') else {
        return;
    };
    let id = raw[1..colon].trim().to_string();
    let rest = raw[colon + 1..].trim();
    let label = rest
        .split(|ch: char| ch.is_whitespace() || ch == '{' || ch == ')')
        .next()
        .unwrap_or("")
        .to_string();
    nodes.push(GgNode {
        id,
        label,
        normalized_properties: normalize_token(rest),
        properties: rest.to_string(),
    });
}

fn count_edges(source: &str) -> usize {
    source.lines().filter(|line| line.contains(")-[")).count()
}

fn is_password_hash(node: &GgNode) -> bool {
    matches!(
        node.label.as_str(),
        "Hash" | "Digest" | "PasswordHash" | "CredentialHash"
    ) && node.normalized_properties.contains("purposepassword")
}

fn is_password_kdf(node: &GgNode) -> bool {
    node.label == "KDF" && node.normalized_properties.contains("purposepassword")
}

fn first_digest_weakness(node: &GgNode) -> Option<&'static str> {
    if !is_password_hash(node) {
        return None;
    }

    if node.normalized_properties.contains("algorithmmd5")
        || node.normalized_properties.contains("algorithmsha1")
        || node.normalized_properties.contains("algorithmsha256")
        || node.normalized_properties.contains("algorithmsha512")
    {
        return Some("fast_hash_surface");
    }

    if node.normalized_properties.contains("saltedfalse") {
        return Some("unsalted_digest");
    }

    if property_number(&node.properties, "bits").is_some_and(|bits| bits < 128) {
        return Some("digest_truncation");
    }

    if node.normalized_properties.contains("toytrue")
        || node.normalized_properties.contains("modetoy")
        || node.normalized_properties.contains("algorithmreduced")
        || node.normalized_properties.contains("algorithmtoy")
    {
        return Some("toy_break");
    }

    None
}

fn first_kdf_weakness(node: &GgNode) -> Option<&'static str> {
    if !is_password_kdf(node) {
        return None;
    }

    let iterations = property_number(&node.properties, "iterations")
        .or_else(|| property_number(&node.properties, "timeCost"));
    let memory_kb = property_number(&node.properties, "memoryKb")
        .or_else(|| property_number(&node.properties, "memoryCostKb"))
        .or_else(|| property_number(&node.properties, "memory"));
    let rounds = property_number(&node.properties, "rounds")
        .or_else(|| property_number(&node.properties, "cost"));
    let work_factor = property_number(&node.properties, "workFactor")
        .or_else(|| property_number(&node.properties, "n"));

    if node.normalized_properties.contains("algorithmpbkdf2")
        && iterations.is_some_and(|value| value < 100_000)
    {
        return Some("low_work_factor");
    }

    if node.normalized_properties.contains("algorithmargon2")
        && (iterations.is_some_and(|value| value < 3)
            || memory_kb.is_some_and(|value| value < 32_768))
    {
        return Some("low_work_factor");
    }

    if node.normalized_properties.contains("algorithmbcrypt")
        && rounds.is_some_and(|value| value < 10)
    {
        return Some("low_work_factor");
    }

    if node.normalized_properties.contains("algorithmscrypt")
        && work_factor.is_some_and(|value| value < 16_384)
    {
        return Some("low_work_factor");
    }

    if node.normalized_properties.contains("toytrue")
        || node.normalized_properties.contains("modetoy")
        || node.normalized_properties.contains("algorithmreduced")
        || node.normalized_properties.contains("algorithmtoy")
    {
        return Some("toy_break");
    }

    None
}

fn push_finding(findings: &mut Vec<Finding>, node: &GgNode, weakness: &'static str) {
    findings.push(Finding {
        family: "recovery-trust",
        claim: "confidentiality",
        weakness,
        severity: if weakness == "toy_break" {
            "warning"
        } else {
            "error"
        },
        node_id: node.id.clone(),
    });
}

fn audit_source(source: &str) -> AuditReport {
    let started = Instant::now();
    let nodes = parse_nodes(source);
    let edge_count = count_edges(source);
    let mut findings = Vec::new();

    for node in &nodes {
        if let Some(weakness) = first_digest_weakness(node) {
            push_finding(&mut findings, node, weakness);
        } else if let Some(weakness) = first_kdf_weakness(node) {
            push_finding(&mut findings, node, weakness);
        }
    }

    let raw_state_upper_bound = nodes.len().saturating_add(edge_count).max(1);
    let representative_count = findings.len().max(1);
    let bracketed_state_upper_bound =
        raw_state_upper_bound.min(nodes.len().max(1).saturating_add(representative_count));
    let pruned_state_estimate = raw_state_upper_bound.saturating_sub(bracketed_state_upper_bound);
    let chaos_pressure_digest = digest_analysis_run(&[
        AnalysisCard {
            phase: FrfStep::Fork,
            world_level: 3,
            seq: nodes.len() as u64,
            twin_dial: Some(TwinVoidDial {
                rim: raw_state_upper_bound as u64,
                void_structural: pruned_state_estimate as u64,
                consensus_fill: bracketed_state_upper_bound as u64,
            }),
            budget: Some(edge_count as u64),
            vent_amt: Some(findings.len() as u64),
        },
        AnalysisCard {
            phase: FrfStep::Race,
            world_level: 5,
            seq: findings.len() as u64,
            twin_dial: None,
            budget: Some(representative_count as u64),
            vent_amt: None,
        },
    ]);

    AuditReport {
        ok: findings.is_empty(),
        conclusion: if findings.is_empty() {
            Conclusion::Secure
        } else {
            Conclusion::WeaknessFound
        },
        node_count: nodes.len(),
        edge_count,
        findings,
        search_bracket: SearchBracket {
            raw_state_upper_bound,
            bracketed_state_upper_bound,
            representative_count,
            pruned_state_estimate,
            chaos_pressure_digest,
        },
        elapsed_nanos: started.elapsed().as_nanos(),
        frf_certified: false,
    }
}

fn audit_path(path: &Path) -> std::io::Result<(AuditReport, ClosedLoopBenchmarkEnvelope)> {
    let source = fs::read_to_string(path)?;
    let (mut report, envelope) = measure_closed_loop_benchmark(
        "crackerjack-rs-audit",
        CLOSED_LOOP_RUNTIME_METADATA_DIRECTIVE,
        || audit_source(&source),
    );
    report.frf_certified = envelope.certified();
    Ok((report, envelope))
}

fn print_smoke(path: &Path) -> std::io::Result<()> {
    let (report, envelope) = audit_path(path)?;
    println!("[crackerjack-rs smoke] target={}", path.display());
    println!(
        "[crackerjack-rs smoke] conclusion={:?} ok={} findings={}",
        report.conclusion,
        report.ok,
        report
            .findings
            .iter()
            .map(|finding| finding.weakness)
            .collect::<Vec<_>>()
            .join(",")
    );
    println!(
        "[crackerjack-rs smoke] raw<={} bracketed<={} pruned~={} chaos={:016x}",
        report.search_bracket.raw_state_upper_bound,
        report.search_bracket.bracketed_state_upper_bound,
        report.search_bracket.pruned_state_estimate,
        report.search_bracket.chaos_pressure_digest
    );
    println!(
        "[crackerjack-rs smoke] elapsed={}ns frf_certified={}",
        envelope.latency_nanos,
        envelope.certified()
    );
    Ok(())
}

fn print_bench(path: &Path, iterations: usize) -> std::io::Result<()> {
    let mut samples = Vec::with_capacity(iterations);
    for _ in 0..iterations {
        let (_, envelope) = audit_path(path)?;
        samples.push(envelope.latency_nanos);
    }
    samples.sort_unstable();
    let mean = samples.iter().sum::<u128>() as f64 / samples.len().max(1) as f64;
    let p50 = percentile(&samples, 0.50);
    let p95 = percentile(&samples, 0.95);
    println!(
        "[crackerjack-rs bench] target={} iterations={} mean={:.3}us p50={:.3}us p95={:.3}us",
        path.display(),
        iterations,
        mean / 1000.0,
        p50 as f64 / 1000.0,
        p95 as f64 / 1000.0
    );
    Ok(())
}

fn percentile(samples: &[u128], p: f64) -> u128 {
    if samples.is_empty() {
        return 0;
    }
    let index = ((samples.len() as f64 * p).ceil() as usize)
        .saturating_sub(1)
        .min(samples.len() - 1);
    samples[index]
}

fn main() -> std::io::Result<()> {
    let args = env::args().collect::<Vec<_>>();
    let mode = parse_mode(&args);
    let iterations = parse_iterations(&args);
    let target = parse_target(&args);

    match mode {
        Mode::Smoke => print_smoke(&target),
        Mode::Bench => print_bench(&target, iterations),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn first_weakness(source: &str) -> Option<&'static str> {
        audit_source(source)
            .findings
            .first()
            .map(|finding| finding.weakness)
    }

    #[test]
    fn flags_fast_md5_password_hashes() {
        assert_eq!(
            first_weakness(include_str!(
                "../../../examples/crypto/password-digest-weak.gg"
            )),
            Some("fast_hash_surface")
        );
        assert_eq!(
            first_weakness(include_str!(
                "../../../examples/crypto/password-digest-md5-toy.gg"
            )),
            Some("fast_hash_surface")
        );
    }

    #[test]
    fn flags_password_digest_family_representatives() {
        assert_eq!(
            first_weakness(include_str!(
                "../../../examples/crypto/password-digest-unsalted-weak.gg"
            )),
            Some("unsalted_digest")
        );
        assert_eq!(
            first_weakness(include_str!(
                "../../../examples/crypto/password-digest-low-work-weak.gg"
            )),
            Some("low_work_factor")
        );
        assert_eq!(
            first_weakness(include_str!(
                "../../../examples/crypto/password-digest-truncated-weak.gg"
            )),
            Some("digest_truncation")
        );
        assert_eq!(
            first_weakness(include_str!(
                "../../../examples/crypto/password-digest-toy.gg"
            )),
            Some("toy_break")
        );
    }

    #[test]
    fn accepts_secure_password_digest_variants() {
        assert!(audit_source(include_str!(
            "../../../examples/crypto/password-digest-secure.gg"
        ))
        .findings
        .is_empty());
        assert!(audit_source(include_str!(
            "../../../examples/crypto/password-digest-low-work-secure.gg"
        ))
        .findings
        .is_empty());
        assert!(audit_source(include_str!(
            "../../../examples/crypto/password-digest-unsalted-secure.gg"
        ))
        .findings
        .is_empty());
    }
}
